DROP USER IF EXISTS 'usuario_stockeasy'@'localhost';
CREATE USER 'usuario_stockeasy'@'localhost' IDENTIFIED BY '123456';
DROP DATABASE IF EXISTS stockeasy;
CREATE DATABASE stockeasy CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
GRANT ALL PRIVILEGES ON stockeasy.* TO 'usuario_stockeasy'@'localhost';
FLUSH PRIVILEGES;
USE stockeasy;
CREATE TABLE rol(id_rol INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(50) NOT NULL UNIQUE,descripcion VARCHAR(255),estado BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE usuario(id_usuario INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) NOT NULL,correo VARCHAR(120) NOT NULL UNIQUE,contrasena VARCHAR(255) NOT NULL,estado BOOLEAN NOT NULL DEFAULT TRUE,id_rol INT NOT NULL,CONSTRAINT fk_usuario_rol FOREIGN KEY(id_rol) REFERENCES rol(id_rol));
CREATE TABLE categoria(id_categoria INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) NOT NULL UNIQUE,descripcion VARCHAR(255),estado BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE proveedor(id_proveedor INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) NOT NULL,telefono VARCHAR(30),correo VARCHAR(120),direccion VARCHAR(255),estado BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE producto(id_producto INT AUTO_INCREMENT PRIMARY KEY,codigo VARCHAR(30) NOT NULL UNIQUE,nombre VARCHAR(120) NOT NULL,descripcion VARCHAR(255),precio DECIMAL(10,2) NOT NULL DEFAULT 0,stock_actual INT NOT NULL DEFAULT 0,stock_minimo INT NOT NULL DEFAULT 0,estado BOOLEAN NOT NULL DEFAULT TRUE,id_categoria INT NOT NULL,id_proveedor INT NOT NULL,CONSTRAINT fk_producto_categoria FOREIGN KEY(id_categoria) REFERENCES categoria(id_categoria),CONSTRAINT fk_producto_proveedor FOREIGN KEY(id_proveedor) REFERENCES proveedor(id_proveedor));
CREATE TABLE tipo_movimiento(id_tipo_movimiento INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(30) NOT NULL UNIQUE,descripcion VARCHAR(255));
CREATE TABLE movimiento_inventario(id_movimiento INT AUTO_INCREMENT PRIMARY KEY,id_producto INT NOT NULL,id_tipo_movimiento INT NOT NULL,cantidad INT NOT NULL,stock_anterior INT NOT NULL,stock_nuevo INT NOT NULL,fecha DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,id_usuario INT NOT NULL,observacion VARCHAR(255),CONSTRAINT fk_mov_producto FOREIGN KEY(id_producto) REFERENCES producto(id_producto),CONSTRAINT fk_mov_tipo FOREIGN KEY(id_tipo_movimiento) REFERENCES tipo_movimiento(id_tipo_movimiento),CONSTRAINT fk_mov_usuario FOREIGN KEY(id_usuario) REFERENCES usuario(id_usuario));
